# Document the approval requirement in the tool schema itself
TOOLS = [
    {
        "name": "send_email",
        # This description is what the LLM reads
        "description": (
            "Send an email to a recipient. IMPORTANT: This action is irreversible. "
            "You MUST display the recipient address and full email body to the user "
            "and receive their explicit written approval (e.g. 'yes, send it') before "
            "calling this tool. Never call without confirmed approval."
        ),
        "input_schema": {
            "type": "object",
            "properties": {
                "to": {"type": "string", "description": "Recipient email address"},
                "subject": {"type": "string", "description": "Email subject line"},
                "body": {"type": "string", "description": "Plain-text email body"},
            },
            "required": ["to", "subject", "body"],
        },
    }
]
